+import { describe, it, expect, beforeEach, vi } from 'vitest';
+import {
+  EmailNotificationAdapter,
+  escapeHtml,
+  EMAIL_TEMPLATES,
+} from '../../src/adapters/email.adapter.js';
+import type { NotificationPayload } from '../../src/models/notification.js';
+
+function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
+  return {
+    id: 'notif-0001',
+    type: 'order-confirmation',
+    channels: ['email'],
+    priority: 'high',
+    recipient: 'alice@example.com',
+    subject: 'Order Confirmation: order-1',
+    body: 'Your order has been placed. Items: Widget x2. Total: $20.00',
+    metadata: { orderId: 'order-1', userId: 'user-1' },
+    createdAt: new Date('2026-01-01'),
+    ...overrides,
+  };
+}
+
+describe('EmailNotificationAdapter', () => {
+  let adapter: EmailNotificationAdapter;
+
+  beforeEach(() => {
+    adapter = new EmailNotificationAdapter();
+  });
+
+  describe('send()', () => {
+    it('should send email for a valid payload with email recipient', async () => {
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(true);
+      expect(result.error).toBeUndefined();
+
+      const emails = adapter.getSentEmails();
+      expect(emails).toHaveLength(1);
+      expect(emails[0]?.to).toBe('alice@example.com');
+      expect(emails[0]?.subject).toContain('Order Confirmation');
+    });
+
+    it('should render HTML body with template', async () => {
+      await adapter.send(makePayload());
+
+      const emails = adapter.getSentEmails();
+      expect(emails[0]?.html).toContain('<h1>Order Confirmed</h1>');
+      expect(emails[0]?.html).toContain('order-1');
+      expect(emails[0]?.html).toContain('TaskFlow Pro');
+    });
+
+    it('should render plain text body', async () => {
+      await adapter.send(makePayload());
+
+      const emails = adapter.getSentEmails();
+      expect(emails[0]?.body).toContain('Order Confirmed');
+      expect(emails[0]?.body).toContain('TaskFlow Pro');
+    });
+
+    it('should fail when recipient is a user ID and no resolver is configured', async () => {
+      const result = await adapter.send(makePayload({ recipient: 'user-1' }));
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Could not resolve recipient');
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+
+    it('should resolve user IDs via recipient resolver', async () => {
+      const resolver = vi.fn().mockResolvedValue('bob@example.com');
+      adapter = new EmailNotificationAdapter({ recipientResolver: resolver });
+
+      const result = await adapter.send(makePayload({ recipient: 'user-1' }));
+
+      expect(result.success).toBe(true);
+      expect(resolver).toHaveBeenCalledWith('user-1');
+      expect(adapter.getSentEmails()[0]?.to).toBe('bob@example.com');
+    });
+
+    it('should fail when resolver returns null', async () => {
+      const resolver = vi.fn().mockResolvedValue(null);
+      adapter = new EmailNotificationAdapter({ recipientResolver: resolver });
+
+      const result = await adapter.send(makePayload({ recipient: 'unknown-user' }));
+
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Could not resolve recipient');
+    });
+
+    it('should skip resolver when recipient is already an email', async () => {
+      const resolver = vi.fn().mockResolvedValue('should-not-be-called@example.com');
+      adapter = new EmailNotificationAdapter({ recipientResolver: resolver });
+
+      await adapter.send(makePayload({ recipient: 'direct@example.com' }));
+
+      expect(resolver).not.toHaveBeenCalled();
+      expect(adapter.getSentEmails()[0]?.to).toBe('direct@example.com');
+    });
+
+    it('should catch transport errors and return failure', async () => {
+      const failingTransport = vi.fn().mockRejectedValue(new Error('SMTP connection failed'));
+      adapter = new EmailNotificationAdapter({ transport: failingTransport });
+
+      const result = await adapter.send(makePayload());
+
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('SMTP connection failed');
+      expect(failingTransport).toHaveBeenCalled();
+    });
+
+    it('should use custom transport when provided', async () => {
+      const customTransport = vi.fn().mockResolvedValue(undefined);
+      adapter = new EmailNotificationAdapter({ transport: customTransport });
+
+      await adapter.send(makePayload());
+
+      expect(customTransport).toHaveBeenCalledTimes(1);
+      const sentMessage = customTransport.mock.calls[0]?.[0];
+      expect(sentMessage.to).toBe('alice@example.com');
+      expect(sentMessage.html).toContain('<h1>');
+    });
+  });
+
+  describe('template rendering', () => {
+    it('should use order-confirmation template', async () => {
+      await adapter.send(makePayload({ type: 'order-confirmation' }));
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toContain('Order Confirmation');
+      expect(email.html).toContain('Order Confirmed');
+    });
+
+    it('should use order-status-update template', async () => {
+      await adapter.send(
+        makePayload({
+          type: 'order-status-update',
+          metadata: { orderId: 'order-1', previousStatus: 'pending', newStatus: 'shipped' },
+        }),
+      );
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toContain('Order Update');
+      expect(email.html).toContain('Order Status Update');
+      expect(email.html).toContain('pending');
+      expect(email.html).toContain('shipped');
+    });
+
+    it('should use welcome template', async () => {
+      await adapter.send(
+        makePayload({
+          type: 'welcome',
+          body: 'Welcome to the platform!',
+        }),
+      );
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toBe('Welcome to TaskFlow Pro!');
+      expect(email.html).toContain('Welcome!');
+      expect(email.html).toContain('first order');
+    });
+
+    it('should use account-update template', async () => {
+      await adapter.send(
+        makePayload({
+          type: 'account-update',
+          body: 'Your email has been changed.',
+        }),
+      );
+
+      const email = adapter.getSentEmails()[0]!;
+      expect(email.subject).toBe('Your Account Has Been Updated');
+      expect(email.html).toContain('Account Updated');
+    });
+  });
+
+  describe('escapeHtml()', () => {
+    it('should escape & < > "', () => {
+      expect(escapeHtml('a & b')).toBe('a &amp; b');
+      expect(escapeHtml('<script>')).toBe('&lt;script&gt;');
+      expect(escapeHtml('"hello"')).toBe('&quot;hello&quot;');
+    });
+
+    it('should not modify safe strings', () => {
+      expect(escapeHtml('hello world')).toBe('hello world');
+    });
+  });
+
+  describe('getSentEmails / clearSentEmails', () => {
+    it('should return a copy of sent emails', async () => {
+      await adapter.send(makePayload());
+
+      const emails1 = adapter.getSentEmails();
+      const emails2 = adapter.getSentEmails();
+      expect(emails1).toEqual(emails2);
+      expect(emails1).not.toBe(emails2); // different array references
+    });
+
+    it('should clear sent emails', async () => {
+      await adapter.send(makePayload());
+      expect(adapter.getSentEmails()).toHaveLength(1);
+
+      adapter.clearSentEmails();
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+  });
+
+  describe('channel property', () => {
+    it('should be "email"', () => {
+      expect(adapter.channel).toBe('email');
+    });
+  });
+});

